35	void RTLIL_BACKEND::dump_attributes(std::ostream &f, std::string indent, const RTLIL::AttrObject *obj)
36	{
37		for (const auto& [name, value] : reversed(obj->attributes)) {
38			f << stringf("%s" "attribute %s ", indent, name);
39			dump_const(f, value);
40			f << stringf("\n");
41		}
42	}
43	
44	void RTLIL_BACKEND::dump_const(std::ostream &f, const RTLIL::Const &data, int width, int offset, bool autoint)
45	{
46		if (width < 0)
47			width = data.size() - offset;
48		if ((data.flags & RTLIL::CONST_FLAG_STRING) == 0 || width != (int)data.size()) {
49			if (width == 32 && autoint) {
50				int32_t val = 0;
51				for (int i = 0; i < width; i++) {
52					log_assert(offset+i < (int)data.size());
53					switch (data[offset+i]) {
54					case State::S0: break;
55					case State::S1: val |= 1 << i; break;
56					default: val = -1; break;
57					}
58				}
59				if (val >= 0) {
60					f << stringf("%d", val);
61					return;
62				}
63			}
64			if ((data.flags & RTLIL::CONST_FLAG_UNSIZED) == 0) {
65				f << stringf("%d'", width);
66			}
67			if (data.flags & RTLIL::CONST_FLAG_SIGNED) {
68				f << stringf("s");
69			}
70			if (data.is_fully_undef_x_only()) {
71				f << "x";
72			} else {
73				for (int i = offset+width-1; i >= offset; i--) {
74					log_assert(i < (int)data.size());
75					switch (data[i]) {
76					case State::S0: f << stringf("0"); break;
77					case State::S1: f << stringf("1"); break;
78					case RTLIL::Sx: f << stringf("x"); break;
79					case RTLIL::Sz: f << stringf("z"); break;
80					case RTLIL::Sa: f << stringf("-"); break;
81					case RTLIL::Sm: f << stringf("m"); break;
82					}
83				}
84			}
85		} else {
86			f << stringf("\"");
87			std::string str = data.decode_string();
88			for (size_t i = 0; i < str.size(); i++) {
89				if (str[i] == '\n')
90					f << stringf("\\n");
91				else if (str[i] == '\t')
92					f << stringf("\\t");
93				else if (str[i] < 32)
94					f << stringf("\\%03o", (unsigned char)str[i]);
95				else if (str[i] == '"')
96					f << stringf("\\\"");
97				else if (str[i] == '\\')
98					f << stringf("\\\\");
99				else
100					f << str[i];
101			}
102			f << stringf("\"");
103		}
104	}
105	
106	void RTLIL_BACKEND::dump_sigchunk(std::ostream &f, const RTLIL::SigChunk &chunk, bool autoint)
107	{
108		if (chunk.wire == NULL) {
109			dump_const(f, chunk.data, chunk.width, chunk.offset, autoint);
110		} else {
111			if (chunk.width == chunk.wire->width && chunk.offset == 0)
112				f << stringf("%s", chunk.wire->name);
113			else if (chunk.width == 1)
114				f << stringf("%s [%d]", chunk.wire->name, chunk.offset);
115			else
116				f << stringf("%s [%d:%d]", chunk.wire->name, chunk.offset+chunk.width-1, chunk.offset);
117		}
118	}
119	
120	void RTLIL_BACKEND::dump_sigspec(std::ostream &f, const RTLIL::SigSpec &sig, bool autoint)
121	{
122		if (sig.is_chunk()) {
123			dump_sigchunk(f, sig.as_chunk(), autoint);
124		} else {
125			f << stringf("{ ");
126			auto chunks = sig.chunks();
127			for (const auto& chunk : reversed(chunks)) {
128				dump_sigchunk(f, chunk, false);
129				f << stringf(" ");
130			}
131			f << stringf("}");
132		}
133	}
134	
135	void RTLIL_BACKEND::dump_wire(std::ostream &f, std::string indent, const RTLIL::Wire *wire)
136	{
137		dump_attributes(f, indent, wire);
138		if (wire->driverCell_) {
139			f << stringf("%s" "# driver %s %s\n", indent,
140					wire->driverCell()->name, wire->driverPort());
141		}
142		f << stringf("%s" "wire ", indent);
143		if (wire->width != 1)
144			f << stringf("width %d ", wire->width);
145		if (wire->upto)
146			f << stringf("upto ");
147		if (wire->start_offset != 0)
148			f << stringf("offset %d ", wire->start_offset);
149		if (wire->port_input && !wire->port_output)
150			f << stringf("input %d ", wire->port_id);
151		if (!wire->port_input && wire->port_output)
152			f << stringf("output %d ", wire->port_id);
153		if (wire->port_input && wire->port_output)
154			f << stringf("inout %d ", wire->port_id);
155		if (wire->is_signed)
156			f << stringf("signed ");
157		f << stringf("%s\n", wire->name);
158	}
159	
160	void RTLIL_BACKEND::dump_memory(std::ostream &f, std::string indent, const RTLIL::Memory *memory)
161	{
162		dump_attributes(f, indent, memory);
163		f << stringf("%s" "memory ", indent);
164		if (memory->width != 1)
165			f << stringf("width %d ", memory->width);
166		if (memory->size != 0)
167			f << stringf("size %d ", memory->size);
168		if (memory->start_offset != 0)
169			f << stringf("offset %d ", memory->start_offset);
170		f << stringf("%s\n", memory->name);
171	}
172	
173	void RTLIL_BACKEND::dump_cell(std::ostream &f, std::string indent, const RTLIL::Cell *cell)
174	{
175		dump_attributes(f, indent, cell);
176		f << stringf("%s" "cell %s %s\n", indent, cell->type, cell->name);
177		for (const auto& [name, param] : reversed(cell->parameters)) {
178			f << stringf("%s  parameter%s%s%s %s ", indent,
179					(param.flags & RTLIL::CONST_FLAG_SIGNED) != 0 ? " signed" : "",
180					(param.flags & RTLIL::CONST_FLAG_REAL) != 0 ? " real" : "",
181					(param.flags & RTLIL::CONST_FLAG_UNSIZED) != 0 ? " unsized" : "",
182					name);
183			dump_const(f, param);
184			f << stringf("\n");
185		}
186		for (const auto& [port, sig] : reversed(cell->connections_)) {
187			f << stringf("%s  connect %s ", indent, port);
188			dump_sigspec(f, sig);
189			f << stringf("\n");
190		}
191		f << stringf("%s" "end\n", indent);
192	}
193	
194	void RTLIL_BACKEND::dump_proc_case_body(std::ostream &f, std::string indent, const RTLIL::CaseRule *cs)
195	{
196		for (const auto& [lhs, rhs] : cs->actions) {
197			f << stringf("%s" "assign ", indent);
198			dump_sigspec(f, lhs);
199			f << stringf(" ");
200			dump_sigspec(f, rhs);
201			f << stringf("\n");
202		}
203	
204		for (const auto& sw : cs->switches)
205			dump_proc_switch(f, indent, sw);
206	}
207	
208	void RTLIL_BACKEND::dump_proc_switch(std::ostream &f, std::string indent, const RTLIL::SwitchRule *sw)
209	{
210		dump_attributes(f, indent, sw);
211	
212		f << stringf("%s" "switch ", indent);
213		dump_sigspec(f, sw->signal);
214		f << stringf("\n");
215	
216		for (const auto case_ : sw->cases)
217		{
218			dump_attributes(f, indent, case_);
219			f << stringf("%s  case ", indent);
220			for (size_t i = 0; i < case_->compare.size(); i++) {
221				if (i > 0)
222					f << stringf(" , ");
223				dump_sigspec(f, case_->compare[i]);
224			}
225			f << stringf("\n");
226	
227			dump_proc_case_body(f, indent + "    ", case_);
228		}
229	
230		f << stringf("%s" "end\n", indent);
231	}
232	
233	void RTLIL_BACKEND::dump_proc_sync(std::ostream &f, std::string indent, const RTLIL::SyncRule *sy)
234	{
235		f << stringf("%s" "sync ", indent);
236		switch (sy->type) {
237		case RTLIL::ST0: f << stringf("low ");
238		if (0) case RTLIL::ST1: f << stringf("high ");
239		if (0) case RTLIL::STp: f << stringf("posedge ");
240		if (0) case RTLIL::STn: f << stringf("negedge ");
241		if (0) case RTLIL::STe: f << stringf("edge ");
242			dump_sigspec(f, sy->signal);
243			f << stringf("\n");
244			break;
245		case RTLIL::STa: f << stringf("always\n"); break;
246		case RTLIL::STg: f << stringf("global\n"); break;
247		case RTLIL::STi: f << stringf("init\n"); break;
248		}
249	
250		for (const auto& [lhs, rhs] : sy->actions) {
251			f << stringf("%s  update ", indent);
252			dump_sigspec(f, lhs);
253			f << stringf(" ");
254			dump_sigspec(f, rhs);
255			f << stringf("\n");
256		}
257	
258		for (auto &it: sy->mem_write_actions) {
259			dump_attributes(f, indent, &it);
260			f << stringf("%s  memwr %s ", indent, it.memid);
261			dump_sigspec(f, it.address);
262			f << stringf(" ");
263			dump_sigspec(f, it.data);
264			f << stringf(" ");
265			dump_sigspec(f, it.enable);
266			f << stringf(" ");
267			dump_const(f, it.priority_mask);
268			f << stringf("\n");
269		}
270	}
271	
272	void RTLIL_BACKEND::dump_proc(std::ostream &f, std::string indent, const RTLIL::Process *proc)
273	{
274		dump_attributes(f, indent, proc);
275		f << stringf("%s" "process %s\n", indent, proc->name);
276		dump_proc_case_body(f, indent + "  ", &proc->root_case);
277		for (auto* sync : proc->syncs)
278			dump_proc_sync(f, indent + "  ", sync);
279		f << stringf("%s" "end\n", indent);
280	}
281	
282	void RTLIL_BACKEND::dump_conn(std::ostream &f, std::string indent, const RTLIL::SigSpec &left, const RTLIL::SigSpec &right)
283	{
284		f << stringf("%s" "connect ", indent);
285		dump_sigspec(f, left);
286		f << stringf(" ");
287		dump_sigspec(f, right);
288		f << stringf("\n");
289	}
290	
291	void RTLIL_BACKEND::dump_module(std::ostream &f, std::string indent, RTLIL::Module *module, RTLIL::Design *design, bool only_selected, bool flag_m, bool flag_n)
292	{
293		bool print_header = flag_m || module->is_selected_whole();
294		bool print_body = !flag_n || !module->is_selected_whole();
295	
296		if (print_header)
297		{
298			dump_attributes(f, indent, module);
299	
300			f << stringf("%s" "module %s\n", indent, module->name);
301	
302			if (!module->avail_parameters.empty()) {
303				if (only_selected)
304					f << stringf("\n");
305				for (const auto &p : module->avail_parameters) {
306					const auto &it = module->parameter_default_values.find(p);
307					if (it == module->parameter_default_values.end()) {
308						f << stringf("%s" "  parameter %s\n", indent, p);
309					} else {
310						f << stringf("%s" "  parameter %s ", indent, p);
311						dump_const(f, it->second);
312						f << stringf("\n");
313					}
314				}
315			}
316		}
317	
318		if (print_body)
319		{
320			for (const auto& [_, wire] : reversed(module->wires_))
321				if (!only_selected || design->selected(module, wire)) {
322					if (only_selected)
323						f << stringf("\n");
324					dump_wire(f, indent + "  ", wire);
325				}
326	
327			for (const auto& [_, mem] : reversed(module->memories))
328				if (!only_selected || design->selected(module, mem)) {
329					if (only_selected)
330						f << stringf("\n");
331					dump_memory(f, indent + "  ", mem);
332				}
333	
334			for (const auto& [_, cell] : reversed(module->cells_))
335				if (!only_selected || design->selected(module, cell)) {
336					if (only_selected)
337						f << stringf("\n");
338					dump_cell(f, indent + "  ", cell);
339				}
340	
341			for (const auto& [_, process] : reversed(module->processes))
342				if (!only_selected || design->selected(module, process)) {
343					if (only_selected)
344						f << stringf("\n");
345					dump_proc(f, indent + "  ", process);
346				}
347	
348			bool first_conn_line = true;
349			for (const auto& [lhs, rhs] : module->connections()) {
350				bool show_conn = !only_selected || design->selected_whole_module(module->name);
351				if (!show_conn) {
352					RTLIL::SigSpec sigs = lhs;
353					sigs.append(rhs);
354					for (auto &c : sigs.chunks()) {
355						if (c.wire == NULL || !design->selected(module, c.wire))
356							continue;
357						show_conn = true;
358					}
359				}
360				if (show_conn) {
361					if (only_selected && first_conn_line)
362						f << stringf("\n");
363					dump_conn(f, indent + "  ", lhs, rhs);
364					first_conn_line = false;
365				}
366			}
367		}
368	
369		if (print_header)
370			f << stringf("%s" "end\n", indent);
371	}
372	
373	void RTLIL_BACKEND::dump_design(std::ostream &f, RTLIL::Design *design, bool only_selected, bool flag_m, bool flag_n)
374	{
375		int init_autoidx = autoidx;
376	
377		if (!flag_m) {
378			int count_selected_mods = 0;
379			for (auto* module : design->modules()) {
380				if (design->selected_whole_module(module->name))
381					flag_m = true;
382				if (design->selected(module))
383					count_selected_mods++;
384			}
385			if (count_selected_mods > 1)
386				flag_m = true;
387		}
388	
389		if (!only_selected || flag_m) {
390			if (only_selected)
391				f << stringf("\n");
392			f << stringf("autoidx %d\n", autoidx);
393		}
394	
395		for (const auto& [_, module] : reversed(design->modules_)) {
396			if (!only_selected || design->selected(module)) {
397				if (only_selected)
398					f << stringf("\n");
399				dump_module(f, "", module, design, only_selected, flag_m, flag_n);
400			}
401		}
402	
403		log_assert(init_autoidx == autoidx);
404	}
405	
406	YOSYS_NAMESPACE_END
407	PRIVATE_NAMESPACE_BEGIN
408	
409	struct RTLILBackend : public Backend {
410		RTLILBackend() : Backend("rtlil", "write design to RTLIL file") { }
411		void help() override
412		{
413			//   |---v---|---v---|---v---|---v---|---v---|---v---|---v---|---v---|---v---|---v---|
414			log("\n");
415			log("    write_rtlil [filename]\n");
416			log("\n");
417			log("Write the current design to an RTLIL file. (RTLIL is a text representation\n");
418			log("of a design in yosys's internal format.)\n");
419			log("\n");
420			log("    -selected\n");
421			log("        only write selected parts of the design.\n");
422			log("\n");
423			log("    -sort\n");
424			log("        sort design in-place (used to be default).\n");
425			log("\n");
426		}
427		void execute(std::ostream *&f, std::string filename, std::vector<std::string> args, RTLIL::Design *design) override
428		{
429			bool selected = false;
430			bool do_sort = false;
431	
432			log_header(design, "Executing RTLIL backend.\n");
433	
434			size_t argidx;
435			for (argidx = 1; argidx < args.size(); argidx++) {
436				std::string arg = args[argidx];
437				if (arg == "-selected") {
438					selected = true;
439					continue;
440				}
441				if (arg == "-sort") {
442					do_sort = true;
443					continue;
444				}
445				break;
446			}
447			extra_args(f, filename, args, argidx);
448	
449			log("Output filename: %s\n", filename);
450	
451			if (do_sort)
452				design->sort();
453	
454			*f << stringf("# Generated by %s\n", yosys_maybe_version());
455			RTLIL_BACKEND::dump_design(*f, design, selected, true, false);
456		}
457	} RTLILBackend;
458	
459	struct DumpPass : public Pass {
460		DumpPass() : Pass("dump", "print parts of the design in RTLIL format") { }
461		void help() override
462		{
463			//   |---v---|---v---|---v---|---v---|---v---|---v---|---v---|---v---|---v---|---v---|
464			log("\n");
465			log("    dump [options] [selection]\n");
466			log("\n");
467			log("Write the selected parts of the design to the console or specified file in\n");
468			log("RTLIL format.\n");
469			log("\n");
470			log("    -m\n");
471			log("        also dump the module headers, even if only parts of a single\n");
472			log("        module is selected\n");
473			log("\n");
474			log("    -n\n");
475			log("        only dump the module headers if the entire module is selected\n");
476			log("\n");
477			log("    -o <filename>\n");
478			log("        write to the specified file.\n");
479			log("\n");
480			log("    -a <filename>\n");
481			log("        like -outfile but append instead of overwrite\n");
482			log("\n");
483		}
484		void execute(std::vector<std::string> args, RTLIL::Design *design) override
485		{
486			std::string filename;
487			bool flag_m = false, flag_n = false, append = false;
488	
489			size_t argidx;
490			for (argidx = 1; argidx < args.size(); argidx++)
491			{
492				std::string arg = args[argidx];
493				if ((arg == "-o" || arg == "-outfile") && argidx+1 < args.size()) {
494					filename = args[++argidx];
495					append = false;
496					continue;
497				}
498				if ((arg == "-a" || arg == "-append") && argidx+1 < args.size()) {
499					filename = args[++argidx];
500					append = true;
501					continue;
502				}
503				if (arg == "-m") {
504					flag_m = true;
505					continue;
506				}
507				if (arg == "-n") {
508					flag_n = true;
509					continue;
510				}
511				break;
512			}
513			extra_args(args, argidx, design);
514	
515			std::ostream *f;
516			std::stringstream buf;
517			bool empty = filename.empty();
518	
519			if (!empty) {
520				rewrite_filename(filename);
521				std::ofstream *ff = new std::ofstream;
522				ff->open(filename, append ? std::ofstream::app : std::ofstream::trunc);
523				if (ff->fail()) {
524					delete ff;
525					log_error("Can't open file `%s' for writing: %s\n", filename, strerror(errno));
526				}
527				f = ff;
528			} else {
529				f = &buf;
530			}
531	
532			RTLIL_BACKEND::dump_design(*f, design, true, flag_m, flag_n);
533	
534			if (!empty) {
535				delete f;
536			} else {
537				log("%s", buf.str());
538			}
539		}
540	} DumpPass;
541	
542	PRIVATE_NAMESPACE_END
