324		RTLIL::Wire *legalize_wire(RTLIL::IdString id)
325		{
326			int wires_size = current_module->wires_size();
327			if (wires_size == 0)
328				error("No wires found for legalization");
329			int hash = hash_ops<RTLIL::IdString>::hash(id).yield();
330			RTLIL::Wire *wire = current_module->wire_at(abs(hash % wires_size));
331			log("Legalizing wire `%s' to `%s'.\n", id.unescape(), wire->name.unescape());
332			return wire;
333		}
