335		RTLIL::SigSpec parse_sigspec()
336		{
337			RTLIL::SigSpec sig;
338	
339			if (try_parse_char('{')) {
340				std::vector<SigSpec> parts;
341				while (!try_parse_char('}'))
342					parts.push_back(parse_sigspec());
343				for (auto it = parts.rbegin(); it != parts.rend(); ++it)
344					sig.append(std::move(*it));
345			} else {
346				// We could add a special path for parsing IdStrings that must already exist,
347				// as here.
348				// We don't need to addref/release in this case.
349				std::optional<RTLIL::IdString> id = try_parse_id();
350				if (id.has_value()) {
351					RTLIL::Wire *wire = current_module->wire(*id);
352					if (wire == nullptr) {
353						if (flag_legalize)
354							wire = legalize_wire(*id);
355						else
356							error("Wire `%s' not found.", *id);
357					}
358					sig = RTLIL::SigSpec(wire);
359				} else {
360					sig = RTLIL::SigSpec(parse_const());
361				}
362			}
363	
364			while (try_parse_char('[')) {
365				int left = parse_integer();
366				if (left >= sig.size() || left < 0) {
367					if (flag_legalize) {
368						int legalized;
369						if (sig.size() == 0)
370							legalized = 0;
371						else
372							legalized = std::max(0, std::min(left, sig.size() - 1));
373						log("Legalizing bit index %d to %d.\n", left, legalized);
374						left = legalized;
375					} else {
376						error("bit index %d out of range", left);
377					}
378				}
379				if (try_parse_char(':')) {
380					int right = parse_integer();
381					if (right < 0) {
382						if (flag_legalize) {
383							log("Legalizing bit index %d to %d.\n", right, 0);
384							right = 0;
385						} else
386							error("bit index %d out of range", right);
387					}
388					if (left < right) {
389						if (flag_legalize) {
390							log("Legalizing bit index %d to %d.\n", left, right);
391							left = right;
392						} else
393							error("invalid slice [%d:%d]", left, right);
394					}
395					if (flag_legalize && left >= sig.size())
396						log("Legalizing slice %d:%d by igoring it\n", left, right);
397					else
398						sig = sig.extract(right, left - right + 1);
399				} else {
400					if (flag_legalize && left >= sig.size())
401						log("Legalizing slice %d by igoring it\n", left);
402					else
403						sig = sig.extract(left);
404				}
405				expect_char(']');
406			}
407	
408			return sig;
409		}
