411		void parse_module()
412		{
413			RTLIL::IdString module_name = parse_id();
414			expect_eol();
415	
416			bool delete_current_module = false;
417			if (design->has(module_name)) {
418				RTLIL::Module *existing_mod = design->module(module_name);
419				if (!flag_overwrite && (flag_lib || (attrbuf.count(ID::blackbox) && attrbuf.at(ID::blackbox).as_bool()))) {
420					log("Ignoring blackbox re-definition of module %s.\n", module_name);
421					delete_current_module = true;
422				} else if (!flag_nooverwrite && !flag_overwrite && !existing_mod->get_bool_attribute(ID::blackbox)) {
423					error("RTLIL error: redefinition of module %s.", module_name);
424				} else if (flag_nooverwrite) {
425					log("Ignoring re-definition of module %s.\n", module_name);
426					delete_current_module = true;
427				} else {
428					log("Replacing existing%s module %s.\n", existing_mod->get_bool_attribute(ID::blackbox) ? " blackbox" : "", module_name);
429					design->remove(existing_mod);
430				}
431			}
432	
433			current_module = new RTLIL::Module;
434			current_module->name = std::move(module_name);
435			current_module->attributes = std::move(attrbuf);
436			if (!delete_current_module)
437				design->add(current_module);
438	
439			while (true)
440			{
441				if (try_parse_keyword("attribute")) {
442					parse_attribute();
443					continue;
444				}
445				if (try_parse_keyword("parameter")) {
446					parse_parameter();
447					continue;
448				}
449				if (try_parse_keyword("connect")) {
450					parse_connect();
451					continue;
452				}
453				if (try_parse_keyword("wire")) {
454					parse_wire();
455					continue;
456				}
457				if (try_parse_keyword("cell")) {
458					parse_cell();
459					continue;
460				}
461				if (try_parse_keyword("memory")) {
462					parse_memory();
463					continue;
464				}
465				if (try_parse_keyword("process")) {
466					parse_process();
467					continue;
468				}
469				if (try_parse_keyword("end")) {
470					expect_eol();
471					break;
472				}
473				error("Unexpected token in module body: %s", error_token());
474			}
475	
476			if (attrbuf.size() != 0)
477				error("dangling attribute");
478			current_module->fixup_ports();
479			if (delete_current_module)
480				delete current_module;
481			else if (flag_lib)
482				current_module->makeblackbox();
483			current_module = nullptr;
484		}
