505		void parse_wire()
506		{
507			RTLIL::Wire *wire;
508			int width = 1;
509			int start_offset = 0;
510			int port_id = 0;
511			bool port_input = false;
512			bool port_output = false;
513			bool upto = false;
514			bool is_signed = false;
515	
516			while (true)
517			{
518				std::optional<RTLIL::IdString> id = try_parse_id();
519				if (id.has_value()) {
520					if (current_module->wire(*id) != nullptr) {
521					  if (flag_legalize) {
522							log("Legalizing redefinition of wire %s.\n", *id);
523							pool<RTLIL::Wire*> wires = {current_module->wire(*id)};
524							current_module->remove(wires);
525						} else
526							error("RTLIL error: redefinition of wire %s.", *id);
527					}
528					wire = current_module->addWire(std::move(*id));
529					break;
530				}
531				if (try_parse_keyword("width")){
532					long long width_val = parse_integer();
533					if (width_val < 0 || width_val >= RTLIL::WIDTH_LIMIT)
534						error("Wire width %lld out of range before `%s`.", width_val, error_token());
535					width = width_val;
536				}
537				else if (try_parse_keyword("upto"))
538					upto = true;
539				else if (try_parse_keyword("signed"))
540					is_signed = true;
541				else if (try_parse_keyword("offset")) {
542					long long offset_val = parse_integer();
543					if (offset_val < INT_MIN || offset_val > INT_MAX)
544						error("Wire offset %lld out of range before `%s`.", offset_val, error_token());
545					start_offset = offset_val;
546				}
547				else if (try_parse_keyword("input")) {
548					port_id = parse_integer();
549					port_input = true;
550				} else if (try_parse_keyword("output")) {
551					port_id = parse_integer();
552					port_output = true;
553				} else if (try_parse_keyword("inout")) {
554					port_id = parse_integer();
555					port_input = true;
556					port_output = true;
557				} else if (try_parse_eol())
558					error("Missing wire ID");
559				else
560					error("Unexpected wire option: %s", error_token());
561			}
562	
563			wire->attributes = std::move(attrbuf);
564			wire->width = width;
565			wire->upto = upto;
566			wire->start_offset = start_offset;
567			wire->is_signed = is_signed;
568			wire->port_id = port_id;
569			wire->port_input = port_input;
570			wire->port_output = port_output;
571			expect_eol();
572		}
