637		void parse_cell()
638		{
639			RTLIL::IdString cell_type = parse_id();
640			RTLIL::IdString cell_name = parse_id();
641			expect_eol();
642	
643			if (current_module->cell(cell_name) != nullptr) {
644				if (flag_legalize) {
645					RTLIL::IdString new_name;
646					int suffix = 1;
647					do {
648						new_name = RTLIL::IdString(cell_name.str() + "_" + std::to_string(suffix));
649						++suffix;
650					} while (current_module->cell(new_name) != nullptr);
651					log("Legalizing redefinition of cell %s by renaming to %s.\n", cell_name, new_name);
652					cell_name = new_name;
653				} else
654					error("RTLIL error: redefinition of cell %s.", cell_name);
655			}
656			RTLIL::Cell *cell = current_module->addCell(cell_name, cell_type);
657			cell->attributes = std::move(attrbuf);
658	
659			while (true)
660			{
661				if (try_parse_keyword("parameter")) {
662					bool is_signed = false;
663					bool is_real = false;
664					bool is_unsized = false;
665					if (try_parse_keyword("signed")) {
666						is_signed = true;
667					} else if (try_parse_keyword("real")) {
668						is_real = true;
669					} else if (try_parse_keyword("unsized")) {
670						is_unsized = true;
671					}
672					RTLIL::IdString param_name = parse_id();
673					RTLIL::Const val = parse_const();
674					if (is_signed)
675						val.flags |= RTLIL::CONST_FLAG_SIGNED;
676					if (is_real)
677						val.flags |= RTLIL::CONST_FLAG_REAL;
678					if (is_unsized)
679						val.flags |= RTLIL::CONST_FLAG_UNSIZED;
680					cell->parameters.insert({std::move(param_name), std::move(val)});
681					expect_eol();
682				} else if (try_parse_keyword("connect")) {
683					RTLIL::IdString port_name = parse_id();
684					if (cell->hasPort(port_name)) {
685						if (flag_legalize)
686							log("Legalizing redefinition of cell port %s.", port_name);
687						else
688							error("RTLIL error: redefinition of cell port %s.", port_name);
689					}
690					cell->setPort(std::move(port_name), parse_sigspec());
691					if (flag_legalize)
692						legalize_width_parameter(cell, port_name);
693					expect_eol();
694				} else if (try_parse_keyword("end")) {
695					expect_eol();
696					break;
697				} else {
698					error("Unexpected token in cell body: %s", error_token());
699				}
700			}
701		}
