703		void parse_connect()
704		{
705			if (attrbuf.size() != 0)
706				error("dangling attribute");
707			RTLIL::SigSpec s1 = parse_sigspec();
708			RTLIL::SigSpec s2 = parse_sigspec();
709			if (flag_legalize) {
710				int min_size = std::min(s1.size(), s2.size());
711				s1 = s1.extract(0, min_size);
712				s2 = s2.extract(0, min_size);
713			}
714			current_module->connect(std::move(s1), std::move(s2));
715			expect_eol();
716		}
