718		void parse_case_body(RTLIL::CaseRule *current_case)
719		{
720			while (true)
721			{
722				if (try_parse_keyword("attribute"))
723					parse_attribute();
724				else if (try_parse_keyword("switch"))
725					parse_switch();
726				else if (try_parse_keyword("assign")) {
727					if (attrbuf.size() != 0)
728						error("dangling attribute");
729					// See https://github.com/YosysHQ/yosys/pull/4765 for discussion on this
730					// warning
731					if (!switch_stack.back()->empty())
732						warning("case rule assign statements after switch statements may cause unexpected behaviour. "
733							"The assign statement is reordered to come before all switch statements.");
734					RTLIL::SigSpec s1 = parse_sigspec();
735					RTLIL::SigSpec s2 = parse_sigspec();
736					current_case->actions.push_back(RTLIL::SigSig(std::move(s1), std::move(s2)));
737					expect_eol();
738				} else
739					return;
740			}
741		}
