743		void parse_switch()
744		{
745			RTLIL::SwitchRule *rule = new RTLIL::SwitchRule;
746			rule->signal = parse_sigspec();
747			rule->attributes = std::move(attrbuf);
748			switch_stack.back()->push_back(rule);
749			expect_eol();
750	
751			while (true) {
752				if (try_parse_keyword("attribute")) {
753					parse_attribute();
754					continue;
755				}
756	
757				if (try_parse_keyword("end")) {
758					expect_eol();
759					break;
760				}
761	
762				expect_keyword("case");
763				RTLIL::CaseRule *case_rule = new RTLIL::CaseRule;
764				case_rule->attributes = std::move(attrbuf);
765				rule->cases.push_back(case_rule);
766				switch_stack.push_back(&case_rule->switches);
767				case_stack.push_back(case_rule);
768	
769				if (!try_parse_eol()) {
770					while (true) {
771						case_rule->compare.push_back(parse_sigspec());
772						if (try_parse_eol())
773							break;
774						expect_char(',');
775					}
776				}
777	
778				parse_case_body(case_rule);
779	
780				switch_stack.pop_back();
781				case_stack.pop_back();
782			}
783		}
