785		void parse_process()
786		{
787			RTLIL::IdString proc_name = parse_id();
788			expect_eol();
789	
790			if (current_module->processes.count(proc_name) != 0) {
791				if (flag_legalize) {
792					log("Legalizing redefinition of process %s.\n", proc_name);
793					current_module->remove(current_module->processes.at(proc_name));
794				} else
795					error("RTLIL error: redefinition of process %s.", proc_name);
796			}
797			RTLIL::Process *proc = current_module->addProcess(std::move(proc_name));
798			proc->attributes = std::move(attrbuf);
799	
800			switch_stack.clear();
801			switch_stack.push_back(&proc->root_case.switches);
802			case_stack.clear();
803			case_stack.push_back(&proc->root_case);
804	
805			parse_case_body(&proc->root_case);
806	
807			while (try_parse_keyword("sync"))
808			{
809				RTLIL::SyncRule *rule = new RTLIL::SyncRule;
810	
811				if (try_parse_keyword("low")) rule->type = RTLIL::ST0;
812				else if (try_parse_keyword("high")) rule->type = RTLIL::ST1;
813				else if (try_parse_keyword("posedge")) rule->type = RTLIL::STp;
814				else if (try_parse_keyword("negedge")) rule->type = RTLIL::STn;
815				else if (try_parse_keyword("edge")) rule->type = RTLIL::STe;
816				else if (try_parse_keyword("always")) rule->type = RTLIL::STa;
817				else if (try_parse_keyword("global")) rule->type = RTLIL::STg;
818				else if (try_parse_keyword("init")) rule->type = RTLIL::STi;
819				else error("Unexpected sync type: %s", error_token());
820	
821				if (rule->type != RTLIL::STa && rule->type != RTLIL::STg && rule->type != RTLIL::STi)
822					rule->signal = parse_sigspec();
823				proc->syncs.push_back(rule);
824				expect_eol();
825	
826				bool attributes_in_update_list = false;
827				while (true)
828				{
829					if (try_parse_keyword("update")) {
830						RTLIL::SigSpec s1 = parse_sigspec();
831						RTLIL::SigSpec s2 = parse_sigspec();
832						rule->actions.push_back(RTLIL::SigSig(std::move(s1), std::move(s2)));
833						expect_eol();
834						continue;
835					}
836	
837					if (try_parse_keyword("attribute")) {
838						attributes_in_update_list = true;
839						parse_attribute();
840						continue;
841					}
842	
843					if (!try_parse_keyword("memwr"))
844						break;
845	
846					RTLIL::MemWriteAction act;
847					act.attributes = std::move(attrbuf);
848					act.memid = parse_id();
849					act.address = parse_sigspec();
850					act.data = parse_sigspec();
851					act.enable = parse_sigspec();
852					act.priority_mask = parse_const();
853					rule->mem_write_actions.push_back(std::move(act));
854					expect_eol();
855				}
856				// The old parser allowed dangling attributes before a "sync" to carry through
857				// the "sync", so we will too, for now.
858				if (attributes_in_update_list && attrbuf.size() > 0)
859					error("dangling attribute");
860			}
861	
862			expect_keyword("end");
863			expect_eol();
864		}
865	
866		RTLILFrontendWorker(RTLIL::Design *design) : design(design) {}
867	
868		void parse(std::istream *f)
869		{
870			this->f = f;
871			line_num = 0;
872			advance_to_next_nonempty_line();
873			while (f->good())
874			{
875				if (try_parse_keyword("attribute")) {
876					parse_attribute();
877					continue;
878				}
879				if (try_parse_keyword("module")) {
880					parse_module();
881					continue;
882				}
883				if (try_parse_keyword("autoidx")) {
884					autoidx = std::max<int>(autoidx, parse_integer());
885					expect_eol();
886					continue;
887				}
888				error("Unexpected token: %s", error_token());
889			}
890			if (attrbuf.size() != 0)
891				error("dangling attribute");
892		}
893	};
894	
895	struct RTLILFrontend : public Frontend {
896		RTLILFrontend() : Frontend("rtlil", "read modules from RTLIL file") { }
897		void help() override
898		{
899			//   |---v---|---v---|---v---|---v---|---v---|---v---|---v---|---v---|---v---|---v---|
900			log("\n");
901			log("    read_rtlil [filename]\n");
902			log("\n");
903			log("Load modules from an RTLIL file to the current design. (RTLIL is a text\n");
904			log("representation of a design in yosys's internal format.)\n");
905			log("\n");
906			log("    -nooverwrite\n");
907			log("        ignore re-definitions of modules. (the default behavior is to\n");
908			log("        create an error message if the existing module is not a blackbox\n");
909			log("        module, and overwrite the existing module if it is a blackbox module.)\n");
910			log("\n");
911			log("    -overwrite\n");
912			log("        overwrite existing modules with the same name\n");
913			log("\n");
914			log("    -lib\n");
915			log("        only create empty blackbox modules\n");
916			log("\n");
917			log("    -legalize\n");
918			log("        prevent semantic errors (e.g. reference to unknown wire, redefinition of wire/cell)\n");
919			log("        by deterministically rewriting the input into something valid. Useful when using\n");
920			log("        fuzzing to generate random but valid RTLIL.\n");
921			log("\n");
922		}
923		void execute(std::istream *&f, std::string filename, std::vector<std::string> args, RTLIL::Design *design) override
924		{
925			RTLILFrontendWorker worker(design);
926	
927			log_header(design, "Executing RTLIL frontend.\n");
928	
929			size_t argidx;
930			for (argidx = 1; argidx < args.size(); argidx++) {
931				std::string arg = args[argidx];
932				if (arg == "-nooverwrite") {
933					worker.flag_nooverwrite = true;
934					worker.flag_overwrite = false;
935					continue;
936				}
937				if (arg == "-overwrite") {
938					worker.flag_nooverwrite = false;
939					worker.flag_overwrite = true;
940					continue;
941				}
942				if (arg == "-lib") {
943					worker.flag_lib = true;
944					continue;
945				}
946				if (arg == "-legalize") {
947					worker.flag_legalize = true;
948					continue;
949				}
950				break;
951			}
952			extra_args(f, filename, args, argidx);
953	
954			log("Input filename: %s\n", filename);
955	
956			worker.parse(f);
957		}
958	} RTLILFrontend;
959	
960	YOSYS_NAMESPACE_END
